class A {
    int a;
    private int b;
    protected int c;

    A(int a, int b, int c) {
        this.a = a;
        this.b = b;
        this.c = c;
    }

    int hap() {
        return a + b + c;
    }
}

class B extends A {
    B(int a, int b, int c) {
        super(a, b, c);
    }

    public int hap() {
        return a * c;
    }
}

public class Main {
    public static void main(String[] args) {
        A aaa = new A(1, 5, 3);
        B bbb = new B(10, 30, 50);
        System.out.printf("%d", aaa.hap() + bbb.hap());
    }
}

#include <stdio.h>

int c(int n) {
    if (n <= 1) return n;
    return c(n - 1) + c(n - 3);
}

int main() {
    printf("%d", c(5));
    return 0;
}

